// // This module simulates a Flash memory cell with a single input for reading data (read_enable) and a 5-bit input for the data (data_in). When read_enable is high, the data_in should be stored in data_out. When read_enable is low, data_out should retain its value.
module flash_memory (
    input wire clk,
    input wire write_enable,
    input wire [4:0] data_in,
    output reg [4:0] data_out
);

    always @(posedge clk) begin
        if (write_enable) begin
            data_out <= data_in;
        end
    end
endmodule
